examples.code:
#include <stdio.h>
int main() {
    FILE *fp = fopen("scores.txt", "w");
    if (fp == NULL) {  // ALWAYS check!
        printf("Error opening file\n");
        return 1;
    }
    fprintf(fp, "Player: Neo\n");
    fprintf(fp, "Score: %d\n", 9500);
    fclose(fp);  // ALWAYS close!
    return 0;
}

#include <stdio.h>
#define BUFSIZE 100
int main() {
    FILE *fp = fopen("scores.txt", "r");
    if (!fp) { perror("fopen"); return 1; }

    char line[BUFSIZE];
    while (fgets(line, BUFSIZE, fp) != NULL) {
        printf("%s", line); // line includes \n
    }
    fclose(fp);
    return 0;
}

// fscanf — reads formatted data:
FILE *fp = fopen("data.txt","r");
char name[50]; int score;
fscanf(fp, "%s %d", name, &score);
printf("%s: %d\n", name, score);
fclose(fp);

// Binary fwrite/fread — entire struct at once:
typedef struct {char name[20]; int score;} Record;
Record r = {"Neo", 9500};
FILE *bf = fopen("data.bin","wb");
fwrite(&r, sizeof(Record), 1, bf);
fclose(bf);

