#include <stdio.h>
#include <errno.h>
#include <string.h>

FILE *fp = fopen("missing.txt", "r");
if (fp == NULL) {
    // errno set by fopen:
    printf("Error: %s\n", strerror(errno));
    // Or use perror:
    perror("fopen");  // prints: fopen: No such file
}

// Function returning error code:
int divide(int a, int b, int *result) {
    if (b == 0) return -1;  // error code
    *result = a / b;
    return 0;  // success
}

