#include <stdlib.h>
#include <stdio.h>

int main() {
    // Allocate array of 5 ints on heap:
    int *arr = malloc(5 * sizeof(int));
    if (arr == NULL) { return 1; }  // check!

    for(int i=0;i<5;i++) arr[i] = i*10;
    printf("%d\n", arr[2]);  // 20

    free(arr);   // MUST free!
    arr = NULL;  // set to NULL after free
    return 0;
}

// calloc — n elements, each of size, zeroed:
int *data = calloc(10, sizeof(int));
// data[0..9] all = 0 ✅

// realloc — resize existing allocation:
data = realloc(data, 20 * sizeof(int));
if (!data) { /* handle error */ }

// ALWAYS check NULL on all allocation calls!
free(data);

